<?php
 namespace WPAICG\Vector\Providers\OpenAI\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_OpenAI_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function connect_logic(AIPKit_Vector_OpenAI_Strategy $strategyInstance, array $config): bool|WP_Error { if (empty($config['api_key'])) { return new WP_Error('missing_api_key', __('OpenAI API Key is required for connection.', 'gpt3-ai-content-generator')); } if (!$strategyInstance->get_is_connected_status()) { return new WP_Error('internal_error_connect_openai', 'Strategy instance not marked as connected before test call.'); } $test_list_response = \WPAICG\Vector\Providers\OpenAI\Methods\_request_logic( $strategyInstance, 'GET', \WPAICG\Core\Providers\OpenAI\OpenAIUrlBuilder::build('vector_stores', [ 'base_url' => $strategyInstance->get_base_url(), 'api_version' => $strategyInstance->get_api_version(), 'limit' => 1 ]) ); if (is_wp_error($test_list_response)) { return $test_list_response; } return true; } 